const dbData = $input.first().json;
const params = $('🔍 Валидация входа').first().json;

const avatarId = params.heygen_avatar_id || dbData.default_avatar_id || '';
const voiceId = params.heygen_voice_id || dbData.default_voice_id || '';
if (!avatarId) throw new Error('HeyGen avatar_id not set');
if (!voiceId) throw new Error('HeyGen voice_id not set');

return [{ json: {
  ...params,
  heygen_background_type: params.heygen_background_type || 'color',
  heygen_avatar_id: avatarId,
  heygen_voice_id: voiceId,
  script_text: dbData.script_text || '',
  timing_marks: dbData.timing_marks || [],
  prompt_text: dbData.prompt_text || '',
  title: dbData.title || '',
  concept: dbData.concept || '',
  visual_description: dbData.visual_description || ''
}}];

