const ctx = $('🔗 Объединение данных').first().json;

// Build background based on background_type
const bgType = ctx.heygen_background_type || 'color';
let background;
if (bgType === 'green_screen') {
  background = { type: 'color', value: '#00B140' };
} else if (bgType === 'image' && ctx.heygen_background) {
  background = { type: 'image', url: ctx.heygen_background };
} else {
  background = { type: 'color', value: ctx.heygen_background || '#f5f5f5' };
}

// Build HeyGen v2 video generation request
const heygenBody = {
  video_inputs: [
    {
      character: {
        type: 'avatar',
        avatar_id: ctx.heygen_avatar_id,
        avatar_style: 'normal'
      },
      voice: {
        type: 'text',
        input_text: ctx.script_text,
        voice_id: ctx.heygen_voice_id,
        speed: 1.0
      },
      background: background
    }
  ],
  dimension: {
    width: ctx.heygen_ratio === '16:9' ? 1920 : 1080,
    height: ctx.heygen_ratio === '16:9' ? 1080 : 1920
  },
  aspect_ratio: ctx.heygen_ratio || '9:16',
  test: false
};

return [{ json: {
  body: JSON.stringify(heygenBody),
  session_id: ctx.session_id
}}];

const response = $input.first().json;
const data = response.data || response;
const videoId = data.video_id;
if (!videoId) throw new Error('HeyGen did not return video_id: ' + JSON.stringify(response).substring(0, 500));

return [{ json: {
  video_id: videoId,
  session_id: $('🏗️ HeyGen запрос').first().json.session_id,
  poll_count: 0
}}];

const prev = $input.first().json;
const status = prev.data?.status || prev.status || 'unknown';
if (status === 'failed') throw new Error('HeyGen video generation failed: ' + JSON.stringify(prev.data?.error || prev));

const pollCount = (prev.poll_count || $('🔑 Извлечь video_id').first().json.poll_count || 0) + 1;
if (pollCount > 60) throw new Error('HeyGen timeout: 60 polls (20 min)');

return [{ json: {
  video_id: prev.video_id || $('🔑 Извлечь video_id').first().json.video_id,
  session_id: prev.session_id || $('🔑 Извлечь video_id').first().json.session_id,
  poll_count: pollCount
}}];

const response = $input.first().json;
const data = response.data || response;
const videoUrl = data.video_url;
if (!videoUrl) throw new Error('HeyGen did not return video_url');

const sessionId = $('🔑 Извлечь video_id').first().json.session_id;

return [{ json: {
  session_id: sessionId,
  raw_video_url: videoUrl,
  heygen_video_id: $('🔑 Извлечь video_id').first().json.video_id
}}];
